TriggerOraclev10g.body:
DECLARE 
envbq_status number;
valor_envbq_update number;
vro_error  tkr_errores%ROWTYPE;
BEGIN
    -- Caso INSERT
    IF INSERTING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_SUBESPECIALIDAD_USU WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_SUBESPECIALIDAD_USU WHERE ID = :NEW.ID AND ENVIO_BQ != 1;
       END IF;    

        INSERT INTO TKRBQ_SUBESPECIALIDAD_USU (
            ENVIO_BQ, ID, ID_ESPECIALIDAD_USUARIO, SUBESPECIALIDAD,
            PROGRAMA_ENTRENAMIENTO, ANHO_FINALIZACION, FECHA_CREACION, ID_SUBESPECIALIDAD
        )
        VALUES (
            0, -- ENVIO_BQ para INSERT
            :NEW.ID, :NEW.ID_ESPECIALIDAD_USUARIO, :NEW.SUBESPECIALIDAD,
            :NEW.PROGRAMA_ENTRENAMIENTO, :NEW.ANHO_FINALIZACION, :NEW.FECHA_CREACION, :NEW.ID_SUBESPECIALIDAD
        );
    END IF;

    -- Caso UPDATE
    IF UPDATING THEN
        SELECT (SELECT ENVIO_BQ FROM TKRBQ_SUBESPECIALIDAD_USU WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NULL THEN

            INSERT INTO TKRBQ_SUBESPECIALIDAD_USU (
                ENVIO_BQ, ID, ID_ESPECIALIDAD_USUARIO, SUBESPECIALIDAD,
                PROGRAMA_ENTRENAMIENTO, ANHO_FINALIZACION, FECHA_CREACION, ID_SUBESPECIALIDAD
            )
            VALUES (
                2, -- ENVIO_BQ para INSERT
                :NEW.ID, :NEW.ID_ESPECIALIDAD_USUARIO, :NEW.SUBESPECIALIDAD,
                :NEW.PROGRAMA_ENTRENAMIENTO, :NEW.ANHO_FINALIZACION, :NEW.FECHA_CREACION, :NEW.ID_SUBESPECIALIDAD
            );       

       ELSE

            IF envbq_status = 0 THEN 
                valor_envbq_update := 0;
            ELSE
                valor_envbq_update := 2;
            END IF;    

            UPDATE TKRBQ_SUBESPECIALIDAD_USU
            SET
                ENVIO_BQ = valor_envbq_update,
                ID = :NEW.ID,
                ID_ESPECIALIDAD_USUARIO = :NEW.ID_ESPECIALIDAD_USUARIO,
                SUBESPECIALIDAD = :NEW.SUBESPECIALIDAD,
                PROGRAMA_ENTRENAMIENTO = :NEW.PROGRAMA_ENTRENAMIENTO,
                ANHO_FINALIZACION = :NEW.ANHO_FINALIZACION,
                FECHA_CREACION = :NEW.FECHA_CREACION,
                ID_SUBESPECIALIDAD = :NEW.ID_SUBESPECIALIDAD
            WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
        END IF;
    END IF;

    -- Caso DELETE
    IF DELETING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_SUBESPECIALIDAD_USU WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_SUBESPECIALIDAD_USU WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
       END IF;    

        INSERT INTO TKRBQ_SUBESPECIALIDAD_USU (
            ENVIO_BQ, ID, ID_ESPECIALIDAD_USUARIO, SUBESPECIALIDAD,
            PROGRAMA_ENTRENAMIENTO, ANHO_FINALIZACION, FECHA_CREACION, ID_SUBESPECIALIDAD
        )
        VALUES (
            -1, -- ENVIO_BQ para DELETE
            :OLD.ID, :OLD.ID_ESPECIALIDAD_USUARIO, :OLD.SUBESPECIALIDAD,
            :OLD.PROGRAMA_ENTRENAMIENTO, :OLD.ANHO_FINALIZACION, :OLD.FECHA_CREACION, :OLD.ID_SUBESPECIALIDAD
        );
    END IF;

    EXCEPTION
        WHEN OTHERS
        THEN
            vro_error.nombre_programa := 'TRG_SYNC_TKR_SUBESPECIALIDAD_USU';
            vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ';
            vro_error.parametros := 'id de consultas: '||:old.id;
            uti_ge_excepciones_pkg.p_grabar_log (vro_error);


END;
